1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	function itemPremium(item: { type: string }): number {
13	  return BASE_PREMIUMS[item.type] + FIRST_INSURANCE_SURCHARGE;
14	}
15	
16	export function quote({ items }: { items: { type: string }[]; years: number; priorContract: boolean }): { premium: number } {
17	  const itemsTotal = items.reduce((sum, item) => sum + itemPremium(item), 0);
18	  return { premium: itemsTotal + PROCESSING_FEE };
19	}
20	
21	export function claim(_input: unknown): unknown {
22	  return undefined;
23	}
